com.mirth.connect.plugins.javascriptstep.script:
if (msg['Parameters']['hosnum'].toString()) {
    tmp['QPD']['QPD.3']['QPD.3.1'] = msg['Parameters']['hosnum'].toString();
} else {
    tmp['QPD']['QPD.3']['QPD.3.1'] = msg['Parameters']['nhsnum'].toString();
}

var xmlrequest = msg['Parameters']['xmlrequest'].toString();

var mappingSteps = {
   "AES": {
       "Waiting for Triage": "WFT",
       "Waiting for Nurse": "WFN",
       "Waiting for Doctor": "WFD",
       "Waiting for ENP": "WFENP",
       "Waiting for Active Triage": "WFDIS",
       "Waiting for Discharge": "WFDIS",
       "Waiting for In CDU": "WFDIS",
       "Waiting for In CDU Blood Test": "WFDIS",
       "Waiting for In CDU Orthoptics": "WFDIS",
       "Waiting for In CDU Visual Fields": "WFDIS",
       "Waiting for In CDU Imaging": "WFDIS",
       "Waiting for In CDU X-ray": "WFDIS",
       "Waiting for In CDU Dilating": "WFDIS",
       "Waiting for In CDU Refraction": "WFDIS",
       "Waiting for In Red Room Nurse": "RR",
       "Waiting for In Red Room Doctor": "RR",
       "In Triage": "WFN",
       "With Nurse": "WFD",
       "With Doctor": "WFDIS",
   },
   "RDCEC": {
       "Waiting for RDCEC Triage": "WFTP",
       "Waiting for RDCEC Nurse": "WFNP",
       "Waiting for RDCEC Doctor": "WFDP",
       "Waiting for RDCEC ENP": "WFENPP",
       "Waiting for RDCEC Discharge": "WFDISP",
       "Waiting for RDCEC Active Triage": "WFDISP",
       "Waiting for In CDU": "WFDISP",
       "Waiting for In CDU Blood Test": "WFDISP",
       "Waiting for In CDU Orthoptics": "WFDISP",
       "Waiting for In CDU Visual Fields": "WFDISP",
       "Waiting for In CDU Imaging": "WFDISP",
       "Waiting for In CDU X-ray": "WFDISP",
       "Waiting for In CDU Dilating": "WFDISP",
       "Waiting for In CDU Refraction": "WFDISP",
       "Waiting for In Red Room Nurse": "RRP",
       "Waiting for In Red Room Doctor": "RRP",
       "In RDCEC Triage": "WFNP",
       "With RDCEC Nurse": "WFDP",
       "With RDCEC Doctor": "WFDISP",
   }
};


function renderSegment(segment, i) {
	for(index in segment) {
		logger.info(index);
		item = segment[index];
		var str_level = index.split('.');
		if(str_level.length==1) {
			if(item != null) {
				tmp[segmentcode][i] = item;
			}
		} else if(str_level.length==2) {
			tmp[segmentcode][i][str_level[0]+'.'+str_level[1]] = item;
		} else if(str_level.length==3) {
			tmp[segmentcode][i][str_level[0]+'.'+str_level[1]][str_level[0]+'.'+str_level[1]+'.'+str_level[2]] = item;
		} else if(str_level.length==4) {
			tmp[segmentcode][i][str_level[0]+'.'+str_level[1]][str_level[0]+'.'+str_level[1]+'.'+str_level[2]][str_level[0]+'.'+str_level[1]+'.'+str_level[2]+'.'+str_level[3]] = item;
		}
	}
}

if (xmlrequest) {
	var json = JSON.parse(XmlUtil.toJson(xmlrequest));
	json = json['root'];
	logger.debug(JSON.stringify(json));
	tmp['MSH']['MSH.9']['MSH.9.1'] = 'ADT';
	prevsegmentcode = "";
	for(segmentcode in json) {
		segment = json[segmentcode];
		if(segmentcode=="event_type") {

			tmp['MSH']['MSH.9']['MSH.9.2'] = segment;
		} else {		
			if(Object.prototype.toString.call(segment) == "[object Object]") {
				createSegment(segmentcode,tmp);
				renderSegment(segment,0);
			} else {
				si_counter = 0;
				for(segmentindex in segment) {
					if(segment[segmentindex] != null) {
						createSegment(segmentcode,tmp,si_counter);
						renderSegment(segment[segmentindex],si_counter);
						si_counter++;
					}
				}
			}
		}
	};

	if(tmp
		&& tmp['PV1']
		&& tmp['PV1']['PV1.3']
		&& tmp['PV1']['PV1.3']['PV1.3.1'].toString().length>0
		&& tmp['PV1']['PV1.3']['PV1.3.2'].toString().length>0
		&& mappingSteps[tmp['PV1']['PV1.3']['PV1.3.1'].toString()][tmp['PV1']['PV1.3']['PV1.3.2'].toString()]) {
			tmp['PV1']['PV1.3']['PV1.3.2'] = mappingSteps[tmp['PV1']['PV1.3']['PV1.3.1'].toString()][tmp['PV1']['PV1.3']['PV1.3.2'].toString()];
	} else {
		logger.error("Invalid location code: "+ tmp['PV1']['PV1.3']['PV1.3.2'].toString());
		tmp['PV1']['PV1.3']['PV1.3.2'] = "";
	}

	//check DG1 datetime
	for( var DG1 in tmp['DG1']) {
		logger.debug(tmp['DG1'][DG1]['DG1.5'].toString());
		if(tmp['DG1'][DG1]['DG1.5'].toString().length < 14 && tmp['DG1'][DG1]['DG1.5'].toString().length >0) {
			tmp['DG1'][DG1]['DG1.5'] = tmp['MSH']['MSH.7']['MSH.7.1'].toString();
		}
	}	
} else {
	tmp['MSH']['MSH.9']['MSH.9.1'] = 'QBP';
	tmp['MSH']['MSH.9']['MSH.9.2'] = 'Q21';
}

com.mirth.connect.plugins.javascriptrule.script:
if(msg['Parameters']['hosnum'].toString() 
|| msg['Parameters']['nhsnum'].toString() 
|| msg['Parameters']['xmlrequest'].toString()
) {
	return true;
}

return false;

properties.script:
var destination = responseMap.get('Send Q21');
var responseMessage = destination.getMessage();

logger.info('responseMessage' + responseMessage);
logger.info(responseMessage);
logger.info((''+responseMessage).length>0);

if(responseMessage && (''+responseMessage).length>0) {
	var Xmsg = new XML(SerializerFactory.getSerializer('HL7V2').toXML(responseMessage));
	logger.info('Q21');
} else {

	var responseMsg = "MSH|^~\&|OpenEyes|RW6|PAS|RW6|20220808155253||QBP^Q21|1659970373855|P|2.4\n"+					"QPD|||0029344";

	var Xmsg = new XML(SerializerFactory.getSerializer('HL7V2').toXML(responseMsg));
	logger.info('A08/A03');		
}
var sResp = ResponseFactory.getSentResponse(Xmsg);
responseMap.put('K21ResponseXML', sResp);

